INSERT INTO `decor_packages` (`id`, `event_type_id`, `name`, `description`, `price`, `image_url`, `status`, `created_at`) VALUES
(1, 1, 'Gói Mặc Định', 'Gói trang trí cơ bản tiêu chuẩn của nhà hàng bao gồm hoa tươi để bàn nhỏ, nến thơm lung linh và setup khăn ăn nghệ thuật.', 200000.00, 'public/assets/images/decors/decor_1.jpg', 'active', '2026-06-12 03:19:25'),
(2, 3, 'Gói Lãng Mạn', 'Tạo không gian vô cùng lãng mạn với bóng bay nghệ thuật bay bổng trần nhà, ánh nến cao cấp và bản nhạc nhẹ nhàng theo yêu cầu.', 500000.00, 'public/assets/images/decors/decor_2.jpg', 'active', '2026-06-12 03:19:25'),
(3, 1, 'Gói Hoàng Gia', 'Khẳng định đẳng cấp với thảm hoa hồng, rượu vang thượng hạng hảo hạng, ánh sáng chuyên nghiệp và backdrop thiết kế riêng.', 3000000.00, 'public/assets/images/decors/decor_3.jpg', 'active', '2026-06-12 03:19:25');
